// test_index.cpp - Git index file tests
// Tests for GitIndex structures and operations
#include "test_harness.h"

// ============================================================================
// Structure Size and Layout Tests
// ============================================================================

TEST(index_entry_sha_size) {
    // SHA field must hold 40 hex chars + null terminator
    TEST_ASSERT_EQ(sizeof(GitIndexEntry::sha), (size_t)(Git::SHA1_HEX_SIZE + 1));
}

TEST(index_entry_path_size) {
    // Path field must match MAX_PATH_LEN
    TEST_ASSERT_EQ(sizeof(GitIndexEntry::path), (size_t)Git::MAX_PATH_LEN);
}

TEST(index_entry_full_sha_size) {
    TEST_ASSERT_EQ(sizeof(GitIndexEntryFull::sha), (size_t)(Git::SHA1_HEX_SIZE + 1));
}

TEST(index_entry_full_path_size) {
    TEST_ASSERT_EQ(sizeof(GitIndexEntryFull::path), (size_t)Git::MAX_PATH_LEN);
}

// ============================================================================
// git_index_remove_path() tests (pure data structure operations)
// ============================================================================

TEST(index_remove_from_empty) {
    GitIndexFull index = {};
    index.entries = nullptr;
    index.entry_count = 0;
    index.capacity = 0;

    bool result = git_index_remove_path(&index, "nonexistent.txt");
    TEST_ASSERT_FALSE(result);  // Path not found
}

TEST(index_remove_nonexistent_path) {
    GitIndexEntryFull* entries = new GitIndexEntryFull[2];
    memset(entries, 0, sizeof(GitIndexEntryFull) * 2);
    strcpy_s(entries[0].path, "file1.txt");
    strcpy_s(entries[1].path, "file2.txt");

    GitIndexFull index = {};
    index.entries = entries;
    index.entry_count = 2;
    index.capacity = 2;

    bool result = git_index_remove_path(&index, "nonexistent.txt");
    TEST_ASSERT_FALSE(result);
    TEST_ASSERT_EQ(index.entry_count, 2);  // Count unchanged

    delete[] entries;
}

TEST(index_remove_first_entry) {
    GitIndexEntryFull* entries = new GitIndexEntryFull[3];
    memset(entries, 0, sizeof(GitIndexEntryFull) * 3);
    strcpy_s(entries[0].path, "aaa.txt");
    strcpy_s(entries[1].path, "bbb.txt");
    strcpy_s(entries[2].path, "ccc.txt");

    GitIndexFull index = {};
    index.entries = entries;
    index.entry_count = 3;
    index.capacity = 3;

    bool result = git_index_remove_path(&index, "aaa.txt");
    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_EQ(index.entry_count, 2);
    TEST_ASSERT_STREQ(index.entries[0].path, "bbb.txt");
    TEST_ASSERT_STREQ(index.entries[1].path, "ccc.txt");

    delete[] entries;
}

