TEST(index_remove_only_entry) {
    GitIndexEntryFull* entries = new GitIndexEntryFull[1];
    memset(entries, 0, sizeof(GitIndexEntryFull));
    strcpy_s(entries[0].path, "only.txt");

    GitIndexFull index = {};
    index.entries = entries;
    index.entry_count = 1;
    index.capacity = 1;

    bool result = git_index_remove_path(&index, "only.txt");
    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_EQ(index.entry_count, 0);

    delete[] entries;
}

// ============================================================================
// git_index_open() tests (require valid repo or graceful failure)
// ============================================================================

TEST(index_open_missing_file) {
    GitRepository repo = {};
    strcpy_s(repo.path, "C:\\nonexistent\\repo\\path");
    strcpy_s(repo.git_dir, "C:\\nonexistent\\repo\\path\\.git");
    repo.is_valid = true;

    GitIndex index = {};
    bool result = git_index_open(&repo, &index);
    TEST_ASSERT_FALSE(result);  // Should fail gracefully for missing file
}

TEST(index_open_full_missing_file) {
    GitRepository repo = {};
    strcpy_s(repo.path, "C:\\nonexistent\\repo\\path");
    strcpy_s(repo.git_dir, "C:\\nonexistent\\repo\\path\\.git");
    repo.is_valid = true;

    GitIndexFull index = {};
    bool result = git_index_open_full(&repo, &index);
    // git_index_open_full returns true for missing index (new repos)
    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_EQ(index.entry_count, 0);
    git_index_close_full(&index);
}

// ============================================================================
// git_index_get_sha() tests
// ============================================================================

TEST(index_get_sha_missing_file) {
    GitRepository repo = {};
    strcpy_s(repo.path, "C:\\nonexistent\\repo\\path");
    strcpy_s(repo.git_dir, "C:\\nonexistent\\repo\\path\\.git");
    repo.is_valid = true;

    char sha[Git::SHA1_HEX_SIZE + 1];
    bool result = git_index_get_sha(&repo, "nonexistent.txt", sha);
    TEST_ASSERT_FALSE(result);  // Should fail gracefully
}
